  });

  describe('upload', () => {
    function setFiles(input: HTMLInputElement, names: string[]): void {
      const dt = new DataTransfer();
      for (const n of names) dt.items.add(new File(['data-' + n], n));
      input.files = dt.files as unknown as FileList;
    }

    /** Drain queued microtasks enough times for the upload loop + re-render. */
    const settle = async (n = 10): Promise<void> => {
      for (let i = 0; i < n; i++) await flush();
    };

    /**
     * Build a fetch impl that rejects POST /upload for the named files (via a
     * non-ok Response, exactly how `ApiClient.request` surfaces failures) while
     * still serving normal browse/upload responses for everything else.
     */
    function failingUploadImpl(failingNames: string[]) {
      const failing = new Set(failingNames);
      return async (url: string, init?: RequestInit): Promise<Response> => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'POST' && u.includes('/upload')) {
          const file = (init?.body as FormData | undefined)?.get('file') as File | null;
          if (file && failing.has(file.name)) {
            return mockResponse({ ok: false, status: 413, text: 'too large' });
          }
          return mockResponse({ status: 200, body: { path: file?.name ?? '' } });
        }
        if (method === 'GET' && u.includes('/browse')) {
          const raw = u.split('path=')[1] ?? '';
          const path = decodeURIComponent(raw);
          const child = 'child-of-' + (path || 'root');
          return mockResponse({
            body: browseResult({
              path,
              entries: [fileEntry({ name: child, path: joinPathHelper(path, child) })],
              fileCount: 1,
              totalSize: 10,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      };
    }

    /** Ordered names of files POSTed to /upload so far. */
    function uploadedFileNames(): string[] {
      return fetchMock.mock.calls
        .filter(([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST')
        .map(([, init]) => ((init?.body as FormData | undefined)?.get('file') as File | null)?.name ?? '');
    }

    /** Count of GET /browse calls observed so far. */
    function browseCount(): number {
      return fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/browse') && (init?.method ?? 'GET') === 'GET',
      ).length;
    }

    it('uploads each selected file to the current browse path, then clears the input and re-renders', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await flush();
      await flush();

      const uploadCalls = fetchMock.mock.calls.filter(
        ([u, init]) => String(u).includes('/upload') && (init?.method ?? 'GET') === 'POST',
      );
      expect(uploadCalls).toHaveLength(2);
      for (const [, init] of uploadCalls) {
        expect(init?.body).toBeInstanceOf(FormData);
        expect((init!.body as FormData).get('file')).toBeInstanceOf(File);
      }
      // All uploads target the current browse path.
      expect(uploadCalls.every(([u]) => String(u).includes('path=' + encodeURIComponent('docs')))).toBe(true);
      // The input is cleared afterwards.
      expect(uploadInput.value).toBe('');
      // And a re-render occurred (browse fetched again after upload).
      const browseCalls = fetchMock.mock.calls.filter(([u]) => String(u).includes('/browse'));
      expect(browseCalls.length).toBeGreaterThan(0);
    });

    it('uploads nothing when no files are selected', async () => {
      const { uploadInput } = setup({ hash: toBrowseHash('docs') });
      await flush();

      uploadInput.dispatchEvent(new Event('change'));
      await flush();

      expect(
        fetchMock.mock.calls.some(([u]) => String(u).includes('/upload')),
      ).toBe(false);
    });

    // ---- per-file error handling -------------------------------------------
    // A single failing upload must NOT abort the remaining uploads, swallow the
    // re-render, or leave the input uncleared. Each failure is surfaced in the
    // status footer (see task spec: "Uploaded N file(s); failed: a.txt, b.txt").

    it('continues uploading the remaining files when a middle upload fails, then clears the input, re-renders, and surfaces the failure', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['b.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['a.txt', 'b.txt', 'c.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      // All three uploads were attempted — including the failing one — in order.
      expect(uploadedFileNames()).toEqual(['a.txt', 'b.txt', 'c.txt']);
      // The input is cleared even though one upload failed.
      expect(uploadInput.value).toBe('');
      // A re-render still happened after the upload loop.
      expect(browseCount()).toBeGreaterThan(browseBefore);
      // The failure is surfaced in the status footer: it names the failing
      // file and acknowledges the two files that did upload.
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('b.txt');
      expect(status.textContent).toMatch(/Uploaded\s+2/i);
      // Successful files are not flagged as failed.
      expect(status.textContent).not.toContain('c.txt');
      expect(status.textContent).not.toContain('a.txt');
    });

    it('continues uploading subsequent files when the first upload fails', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['bad.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['bad.txt', 'good.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['bad.txt', 'good.txt']);
      expect(uploadInput.value).toBe('');
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('bad.txt');
      expect(status.textContent).not.toContain('good.txt');
    });

    it('clears the input, re-renders, and lists every failure when all uploads fail', async () => {
      fetchMock.mockImplementation(failingUploadImpl(['x.txt', 'y.txt']));
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();
      const browseBefore = browseCount();

      setFiles(uploadInput, ['x.txt', 'y.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadedFileNames()).toEqual(['x.txt', 'y.txt']);
      expect(uploadInput.value).toBe('');
      expect(browseCount()).toBeGreaterThan(browseBefore);
      expect(status.textContent).toMatch(/failed/i);
      expect(status.textContent).toContain('x.txt');
      expect(status.textContent).toContain('y.txt');
    });

    it('does not surface a failure message when every upload succeeds (status stays the normal browse summary)', async () => {
      const { uploadInput, status } = setup({ hash: toBrowseHash('docs') });
      await flush();

      setFiles(uploadInput, ['a.txt', 'b.txt']);
      uploadInput.dispatchEvent(new Event('change'));
      await settle();

      expect(uploadInput.value).toBe('');
      // No failure report; renderBrowse's normal "N folders, M files, total S"
      // summary is what the re-render leaves behind.
      expect(status.textContent).not.toMatch(/failed/i);
      expect(status.textContent).toMatch(/folders.*files.*total/);
    });
  });
});

/* ===========================================================================
 * Import characterization (safety net for unused-import removal)
 *
 * `src/app.ts` imports `parseHash` (from ./router.js), `parentPath`, and
 * `basename` (from ./format.js) that are never referenced in the module body
 * and are slated for removal. Removing unused imports cannot change runtime
 * behavior, so these tests guard the OTHER behaviors: they pin the observable
 * outputs that depend on the imports which STAY — especially the ones that
 * share an import line with the removed names, where a careless edit could
 * drop a needed sibling. Each assertion checks a concrete value tied to one
 * retained import's real usage in the app; if that import were removed, the
 * referenced call would throw (ReferenceError) or emit wrong output and the
 * test would fail.
 *
 * Retained imports exercised here:
 *   format.js: joinPath, normalizeRelativePath, formatBytes, formatDate
 *   router.js: toBrowseHash, toSearchHash
 * (getCurrentRoute / subscribe / navigate are already covered by the render
 * orchestration and toolbar-handler suites above.)
 * ========================================================================= */
describe('import characterization (KEEP-list behaviors)', () => {
  // Local leaf finder; the breadcrumb describe has its own scoped copy.
  function leafByText(container: Element, text: string): HTMLElement | undefined {
    return Array.from(container.querySelectorAll('*')).find(
      (el) => el.children.length === 0 && (el.textContent ?? '').trim() === text,
    ) as HTMLElement | undefined;
  }

  /* --- format.js KEEP imports (siblings of the removed parentPath/basename) --- */

  describe('joinPath (breadcrumb cumulative paths)', () => {
    it('joins each cumulative segment across three path levels', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: 'a/b/c', entries: [] }));

      leafByText(breadcrumb, 'c')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b/c'));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('normalizeRelativePath (breadcrumb path cleaning)', () => {
    it('collapses leading/doubled/trailing slashes before splitting segments', async () => {
      const { breadcrumb } = await setupCleared();
      renderBrowse(browseResult({ path: '//a//b//' }));

      leafByText(breadcrumb, 'b')!.click();
      expect(window.location.hash).toBe(toBrowseHash('a/b'));
    });
  });

  describe('formatBytes (size column)', () => {
    it('renders a 0-byte file as "0 B" (sub-KB integer branch)', async () => {
      const entry = fileEntry({ name: 'empty.txt', path: 'docs/empty.txt', size: 0 });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const sizeCell = cellsOf(rowByName(results.querySelector('table')!, 'empty.txt')!)[1];
      expect(sizeCell.textContent?.trim()).toBe('0 B');
    });
  });

  describe('formatDate (modified column)', () => {
    it('renders an empty Modified cell when lastModified is empty (fallback)', async () => {
      const entry = fileEntry({ name: 'nodate.txt', path: 'docs/nodate.txt', lastModified: '' });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [entry] }));

      const modifiedCell = cellsOf(rowByName(results.querySelector('table')!, 'nodate.txt')!)[2];
      expect(modifiedCell.textContent).toBe('');
    });
  });

  /* --- router.js KEEP imports (siblings of the removed parseHash) --- */

  describe('toBrowseHash (per-segment percent-encoding)', () => {
    it('encodes spaces in directory names when navigating into a folder', async () => {
      const dir = fileEntry({ name: 'my folder', path: 'docs/my folder', isDirectory: true });
      const { results } = await setupCleared();
      renderBrowse(browseResult({ path: 'docs', entries: [dir] }));

      clickNameLink(rowByName(results.querySelector('table')!, 'my folder')!);

      expect(window.location.hash).toBe('#/browse/docs/' + encodeURIComponent('my folder'));
      expect(window.location.hash).toBe(toBrowseHash('docs/my folder'));
    });
  });

  describe('toSearchHash (query/path percent-encoding)', () => {
    it('encodes special characters in the search query and scope path', async () => {
      const { searchInput, searchBtn } = setup({ hash: toBrowseHash('docs') });
      await flush();

      searchInput.value = 'a & b=c?';
      searchBtn.click();

      const expected =
        '#/search?q=' + encodeURIComponent('a & b=c?') + '&path=' + encodeURIComponent('docs');
      expect(window.location.hash).toBe(expected);
      expect(window.location.hash).toBe(toSearchHash('a & b=c?', 'docs'));
    });
  });
});

/* ===========================================================================
 * Rendering lifecycle
 *
 * Two interrelated startApp/render bugs are pinned here:
 *
 *  (a) LISTENER LEAK — startApp calls subscribe(render) and used to throw away
 *      the returned unsubscribe function, so every re-mount left the previous
 *      mount's hashchange listener on `window`. (happy-dom dedups identical
 *      function references, so this leak is latent rather than multiplicative
 *      in this environment, but the cleanup contract is still asserted via the
 *      addEventListener/removeEventListener spies below.)
 *  (b) RENDER RACE — render() is async; two rapid navigations let a slower
 *      fetch overwrite a fresher one's results. The fix aborts a superseded
 *      render after each await.
 * ========================================================================= */
describe('rendering lifecycle', () => {
  describe('hashchange listener cleanup on re-mount', () => {
    /**
     * Mount the app `n` times into fresh containers, the way `setup()` does.
     * Returns nothing; used to drive repeated startApp() calls with the spies
     * already installed so every subscribe/unsubscribe is captured.
     */
    function mountNTimes(n: number): void {
      for (let i = 0; i < n; i++) {
        document.body.innerHTML = '';
        window.location.hash = '';
        const root = document.createElement('div');
        document.body.append(root);
        startApp(root);
      }
    }

    function hashchangeCalls(
      spy: ReturnType<typeof vi.spyOn>,
    ): Array<{ type: string; callback: EventListenerOrEventListenerObject }> {
      return spy.mock.calls
        .map(([type, callback]) => ({ type: String(type), callback }))
        .filter((c) => c.type === 'hashchange');
    }

    it('subscribes exactly one hashchange listener per mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');

      mountNTimes(3);
      await flush();

      // Each startApp() subscribes render exactly once.
      expect(hashchangeCalls(addSpy)).toHaveLength(3);
    });

    it('unsubscribes the previous mount\'s hashchange listener on every re-mount', async () => {
      const addSpy = vi.spyOn(window, 'addEventListener');
      const removeSpy = vi.spyOn(window, 'removeEventListener');

      const N = 4;
      mountNTimes(N);
      await flush();

      const adds = hashchangeCalls(addSpy);
      const removes = hashchangeCalls(removeSpy);

      // Robust to test ordering: the 1st mount in *this* test may additionally
      // tear down a listener left over by an earlier test, so we only assert a
      // lower bound. The invariant that matters is that every re-mount removes
      // its predecessor — i.e. at least (N − 1) hashchange removals happened.
      // The leaky implementation performs ZERO removals.
      expect(adds).toHaveLength(N);
      expect(removes.length).toBeGreaterThanOrEqual(N - 1);
      // Every removal targets the same render callback that was subscribed.
      expect(removes.length).toBeGreaterThan(0);
      for (const r of removes) {
        expect(typeof r.callback).toBe('function');
        expect(adds.some((a) => a.callback === r.callback)).toBe(true);
      }
    });
  });

  describe('render race (superseded fetch is discarded)', () => {
    /**
     * Drive a browse render for `path` whose fetch is held open until the
     * caller invokes `release()`. All other browse paths resolve immediately.
     */
    function stubHeldBrowse(
      heldPath: string,
    ): { release: () => void } {
      let release!: () => void;
      const held = new Promise<Response>((resolve) => {
        release = () =>
          resolve(
            mockResponse({
              body: browseResult({
                path: heldPath,
                entries: [
                  fileEntry({
                    name: 'child-of-' + heldPath,
                    path: joinPathHelper(heldPath, 'child-of-' + heldPath),
                  }),
                ],
                fileCount: 1,
                totalSize: 1,
              }),
            }),
          );
      });

      fetchMock.mockImplementation(async (url, init) => {
        const u = String(url);
        const method = (init?.method ?? 'GET').toUpperCase();
        if (method === 'GET' && u.includes('/browse')) {
          const path = decodeURIComponent(u.split('path=')[1] ?? '');
          if (path === heldPath) {
            return held;
          }
          return mockResponse({
            body: browseResult({
              path,
              entries: [
                fileEntry({
                  name: 'child-of-' + path,
                  path: joinPathHelper(path, 'child-of-' + path),
                }),
              ],
              fileCount: 1,
              totalSize: 1,
            }),
          });
        }
        return mockResponse({ status: 200, body: {} });
      });

      return { release };
    }

    it('does not let a slower, superseded browse overwrite the latest results', async () => {
      const { release } = stubHeldBrowse('slow');

      const { results } = setup();
      await flush(); // settle the initial render for the default route

      // Navigate to 'slow' (its fetch is held), then — before it resolves — to
      // 'fast'. In happy-dom each hash assignment fires `hashchange` and thus
      // render() synchronously, so both fetches are issued in order and the
      // 'slow' render is suspended at its await when 'fast' starts.
      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush(); // 'fast' resolves first and commits

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');

      // The slow fetch finally resolves LAST. Its stale data must be discarded
      // (a newer render owns the slot) and must NOT clobber the fresh results.
      release();
      await flush();

      expect(results.textContent).toContain('child-of-fast');
      expect(results.textContent).not.toContain('child-of-slow');
    });

    it('does not let a superseded browse update the breadcrumb or status', async () => {
      const { release } = stubHeldBrowse('slow');

      const { breadcrumb, status } = setup();
      await flush();

      navigate(toBrowseHash('slow'));
      navigate(toBrowseHash('fast'));
      await flush();

      // The fresh render owns the breadcrumb / status for 'fast'.
      expect(breadcrumb.textContent).toContain('fast');
      expect(status.textContent).toContain('1 files');

      release();
      await flush();

      // The superseded 'slow' render must not have touched them.
      expect(breadcrumb.textContent).toContain('fast');
      expect(breadcrumb.textContent).not.toContain('slow');
      expect(status.textContent).toContain('1 files');
    });

    it('still renders the latest navigation when fetches resolve in order', async () => {
      // Control case: a single navigation (no race) still commits normally,
      // so the race guard does not swallow a non-superseded render.
      const { results } = setup({ hash: toBrowseHash('solo') });
      await flush();

      expect(results.textContent).toContain('child-of-solo');

      navigate(toBrowseHash('next'));
      await flush();

      expect(results.textContent).toContain('child-of-next');
      expect(results.textContent).not.toContain('child-of-solo');
    });
  });
});

export interface FileEntry {
  name: string;
  path: string;
  isDirectory: boolean;
  size: number;
  lastModified: string;
}

export interface BrowseResult {
  path: string;
  parent: string | null;
  entries: FileEntry[];
  folderCount: number;
  fileCount: number;
  totalSize: number;
}

export interface SearchResult {
  query: string;
  path: string;
  results: FileEntry[];
}

export class ApiClient {
  constructor(private readonly baseUrl: string = '/api/files') {}

  async browse(path: string): Promise<BrowseResult> {
    return this.request<BrowseResult>(
      `${this.baseUrl}/browse?path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async search(query: string, path: string): Promise<SearchResult> {
    return this.request<SearchResult>(
      `${this.baseUrl}/search?query=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`,
      { method: 'GET' }
    );
  }

  async upload(path: string, file: File): Promise<{ path: string }> {
    const formData = new FormData();
    formData.append('file', file);
    return this.request<{ path: string }>(
      `${this.baseUrl}/upload?path=${encodeURIComponent(path)}`,
      { method: 'POST', body: formData }
    );
  }

  async delete(path: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/delete?path=${encodeURIComponent(path)}`,
      { method: 'DELETE' }
    );
  }

  async move(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/move`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  async copy(source: string, destination: string): Promise<void> {
    await this.request<unknown>(
      `${this.baseUrl}/copy`,
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ sourcePath: source, destinationPath: destination }),
      }
    );
  }

  downloadUrl(path: string): string {
    return `${this.baseUrl}/download?path=${encodeURIComponent(path)}`;
  }

  private async request<T>(url: string, init?: RequestInit): Promise<T> {
    const res = await fetch(url, init);
    if (!res.ok) {
      throw new Error(res.status + ': ' + await res.text());
    }
    return await res.json() as T;
  }
}

export type View = 'browse' | 'search';

export interface Route {
  view: View;
  path: string;
  query: string;
}

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

/**
 * Parse a full hash (including leading '#') into a Route.
 *
 * Browse format:  #/browse  or  #/browse/<segments>
 * Search format:  #/search?q=<query>&path=<path>
 * Anything else returns the default browse route.
 */
export function parseHash(hash: string): Route {
  if (hash.startsWith('#/browse')) {
    const afterPrefix = hash.slice('#/browse'.length); // everything after "#/browse"
    // Remove the leading '/' if present, then URL-decode what remains
    const path = afterPrefix.startsWith('/')
      ? decodeURIComponent(afterPrefix.slice(1))
      : decodeURIComponent(afterPrefix);
    return { view: 'browse', path, query: '' };
  }

  if (hash.startsWith('#/search')) {
    const queryString = hash.slice('#/search'.length);
    const params = new URLSearchParams(queryString);
    const query = params.get('q') ?? '';
    const path = params.get('path') ?? '';
    return { view: 'search', query, path };
  }

  return DEFAULT_ROUTE;
}

/**
 * Serialize a browse path into a browse hash.
 * Each segment is independently percent-encoded.
 */
export function toBrowseHash(path: string): string {
  if (path === '') {
    return '#/browse';
  }
  const segments = path.split('/');
  const encoded = segments.map((s) => encodeURIComponent(s)).join('/');
  return '#/browse/' + encoded;
}

/**
 * Serialize query and path values into a search hash.
 * Both values are percent-encoded.
 */
export function toSearchHash(query: string, path: string): string {
  return `#/search?q=${encodeURIComponent(query)}&path=${encodeURIComponent(path)}`;
}

/**
 * Read the current route from window.location.hash.
 */
export function getCurrentRoute(): Route {
  return parseHash(window.location.hash);
}

/**
 * Subscribe to hash-change events.
 * Returns an unsubscribe function.
 */
export function subscribe(callback: () => void): () => void {
  window.addEventListener('hashchange', callback);
  return () => {
    window.removeEventListener('hashchange', callback);
  };
}

/**
 * Navigate to a given hash (sets window.location.hash).
 */
export function navigate(hash: string): void {
  window.location.hash = hash;
}

/**
 * Pure formatting helpers for the file browser UI.
 *
 * Every function in this module is side-effect free (no DOM access, no network)
 * so each can be unit-tested in isolation. The module exports ONLY the six
 * functions declared here.
 */

/** Binary (1024-based) byte-unit suffixes, from bytes up to terabytes. */
const BYTE_UNITS = ["B", "KB", "MB", "GB", "TB"] as const;

/**
 * Format a byte count as a human-readable string using binary (1024-based)
 * units.
 *
 * - Values below 1024 render as an integer byte count, e.g. `0 B`, `1023 B`.
 * - Values of 1024 and above render with exactly one decimal place, keeping a
 *   trailing `.0`, e.g. `1.0 KB`, `1.5 KB`, `1.0 MB`.
 *
 * The unit caps at `TB`; values beyond 1024 TB remain expressed in terabytes.
 */
export function formatBytes(bytes: number): string {
    const units = BYTE_UNITS;
    let value = bytes;
    let unitIndex = 0;

    while (value >= 1024 && unitIndex < units.length - 1) {
        value /= 1024;
        unitIndex++;
    }

    if (unitIndex === 0) {
        // Below the KB boundary: render as an integer byte count.
        return `${Math.round(value)} ${units[unitIndex]}`;
    }

    // KB and above: one decimal place (trailing .0 preserved per spec).
    return `${value.toFixed(1)} ${units[unitIndex]}`;
}

/**
 * Normalize a relative path into a clean, slash-joined form.
 *
 * - backslashes (`\`) become forward slashes
 * - leading/trailing slashes are trimmed
 * - runs of repeated slashes collapse to one
 * - `.` and `..` segments are dropped (filtered out, NOT resolved against the
 *   parent — this also neutralizes path-traversal segments)
 * - empty/root input collapses to `""`
 */
export function normalizeRelativePath(path: string): string {
    return path
        .replace(/\\/g, "/")
        .split("/")
        .filter((segment) => segment !== "" && segment !== "." && segment !== "..")
        .join("/");
}

/**
 * Join two path fragments with a single separating slash, then normalize the
 * result (see {@link normalizeRelativePath}).
 */
export function joinPath(base: string, name: string): string {
    return normalizeRelativePath(`${base}/${name}`);
}

/**
 * Return the normalized parent relative path, or `""` when the path is already
 * at root (empty or a single segment after normalization).
 */
export function parentPath(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? "" : normalized.slice(0, lastSlash);
}

/**
 * Return the last segment of a normalized path. Returns `""` for an empty
 * path.
 */
export function basename(path: string): string {
    const normalized = normalizeRelativePath(path);
    const lastSlash = normalized.lastIndexOf("/");
    return lastSlash === -1 ? normalized : normalized.slice(lastSlash + 1);
}

/** Left-pad a number to two digits with a leading zero. */
function padTwo(value: number): string {
    return String(value).padStart(2, "0");
}

/**
 * Format an ISO 8601 date string as `yyyy-MM-dd HH:mm` (local calendar time).
 *
 * Returns `""` for empty or unparseable input instead of throwing.
 */
export function formatDate(iso: string): string {
    if (!iso) {
        return "";
    }

    const date = new Date(iso);
    if (Number.isNaN(date.getTime())) {
        return "";
    }

    const year = date.getFullYear();
    const month = padTwo(date.getMonth() + 1);
    const day = padTwo(date.getDate());
    const hours = padTwo(date.getHours());
    const minutes = padTwo(date.getMinutes());

    return `${year}-${month}-${day} ${hours}:${minutes}`;
}

// @vitest-environment node

/**
 * Pure-function tests for the router's parsers and serializers.
 *
 * This file is pinned to the `node` environment (see the docblock above) on
 * purpose: the spec requires the pure helpers to be "unit-testable without a
 * DOM". Running them here — with no `window`, `document`, or happy-dom shim
 * available — guarantees that `parseHash`, `toBrowseHash`, and `toSearchHash`
 * (and therefore their importing module at load time) introduce no DOM
 * dependency. The DOM-bound helpers are covered separately in
 * `router.dom.test.ts`.
 */
import { describe, it, expect } from 'vitest';
import {
  parseHash,
  toBrowseHash,
  toSearchHash,
  type Route,
  type View,
} from './router';

const DEFAULT_ROUTE: Route = { view: 'browse', path: '', query: '' };

describe('parseHash', () => {
  describe('browse routes', () => {
    it('parses #/browse with no segments to an empty path', () => {
      expect(parseHash('#/browse')).toEqual(DEFAULT_ROUTE);
    });

    it('parses #/browse/ (trailing slash, no segments) to an empty path', () => {
      expect(parseHash('#/browse/')).toEqual(DEFAULT_ROUTE);
    });

    it('parses a single segment', () => {
      expect(parseHash('#/browse/docs')).toEqual({ view: 'browse', path: 'docs', query: '' });
    });

    it('joins multiple segments with /', () => {
      expect(parseHash('#/browse/docs/2024/reports')).toEqual({
        view: 'browse',
        path: 'docs/2024/reports',
        query: '',
      });
    });

    it('URL-decodes percent-encoded characters', () => {
      expect(parseHash('#/browse/hello%20world')).toEqual({
        view: 'browse',
        path: 'hello world',
        query: '',
      });
    });

    it('decodes each segment independently', () => {
      expect(parseHash('#/browse/a%20b/c%20d')).toEqual({
        view: 'browse',
        path: 'a b/c d',
        query: '',
      });
    });

    it('decodes an encoded slash (%2F) within a segment', () => {
      expect(parseHash('#/browse/sub%2Ffolder')).toEqual({
        view: 'browse',
        path: 'sub/folder',
        query: '',
      });
    });

    it('preserves a trailing slash in the decoded path', () => {
      expect(parseHash('#/browse/docs/')).toEqual({ view: 'browse', path: 'docs/', query: '' });
    });

    it('decodes multi-byte (unicode) percent sequences', () => {
      // 'café' encoded as UTF-8
      expect(parseHash('#/browse/caf%C3%A9')).toEqual({
        view: 'browse',
        path: 'café',
        query: '',
      });
    });
  });

  describe('search routes', () => {
    it('parses both query and path params', () => {
      expect(parseHash('#/search?q=hello&path=docs')).toEqual({
        view: 'search',
        query: 'hello',
        path: 'docs',
      });
    });

    it('defaults path to an empty string when absent', () => {
      expect(parseHash('#/search?q=hello')).toEqual({
        view: 'search',
        query: 'hello',
        path: '',
      });
    });

    it('defaults query to an empty string when absent', () => {
      expect(parseHash('#/search?path=docs')).toEqual({
        view: 'search',
        query: '',
        path: 'docs',
      });
    });

    it('treats #/search with no query string as an empty search', () => {
      expect(parseHash('#/search')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats #/search? (bare question mark) as an empty search', () => {
      expect(parseHash('#/search?')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty q= as an empty query', () => {
      expect(parseHash('#/search?q=')).toEqual({ view: 'search', query: '', path: '' });
    });

    it('treats an explicitly empty path= as an empty path', () => {
      expect(parseHash('#/search?q=hi&path=')).toEqual({
        view: 'search',
        query: 'hi',
        path: '',
      });
    });

    it('URL-decodes encoded query and path values', () => {
      expect(parseHash('#/search?q=hello%20world&path=my%20docs')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'my docs',
      });
    });

    it('decodes a "+" in the query as a space (URLSearchParams behavior)', () => {
      expect(parseHash('#/search?q=hello+world&path=x')).toEqual({
        view: 'search',
        query: 'hello world',
        path: 'x',
      });
    });

    it('keeps an unencoded slash in path= intact', () => {
      expect(parseHash('#/search?q=a&path=docs/2024')).toEqual({
        view: 'search',
        query: 'a',
        path: 'docs/2024',
      });
    });

    it('returns the first value when a param is repeated', () => {
      // URLSearchParams.get() yields the first occurrence.
      expect(parseHash('#/search?q=a&q=b&path=c')).toEqual({
        view: 'search',
        query: 'a',
        path: 'c',
      });
    });

    it('decodes multi-byte (unicode) values', () => {
      expect(parseHash('#/search?q=caf%C3%A9&path=%C3%B1')).toEqual({
        view: 'search',
        query: 'café',
        path: 'ñ',
      });
    });
  });

  describe('fallback for unrecognized hashes', () => {
    it.each<[string, string]>([
      ['an empty string', ''],
      ['a lone hash', '#'],
      ['a hash-slash only', '#/'],
      ['an unknown view', '#/home'],
      ['a string with no leading hash', 'garbage'],
      ['browse missing the leading slash (#browse)', '#browse'],
      ['a completely unrelated fragment', '#section-1'],
    ])('returns the default browse route for %s', (_label, hash) => {
      expect(parseHash(hash)).toEqual(DEFAULT_ROUTE);
    });
  });

  describe('returned shape', () => {
    it('always returns an object with exactly view, path, and query', () => {
      const route = parseHash('#/browse/a');
      expect(route).toHaveProperty('view');
      expect(route).toHaveProperty('path');
      expect(route).toHaveProperty('query');
      expect(Object.keys(route).sort()).toEqual(['path', 'query', 'view']);
    });

    it('produces view values assignable to the View union', () => {
      const browseView: View = parseHash('#/browse').view;
      const searchView: View = parseHash('#/search?q=a').view;
      expect([browseView, searchView]).toEqual(['browse', 'search']);
    });
  });
});

describe('toBrowseHash', () => {
  it('returns #/browse for an empty path', () => {
    expect(toBrowseHash('')).toBe('#/browse');
  });

  it('returns #/browse/<segment> for a single segment', () => {
    expect(toBrowseHash('docs')).toBe('#/browse/docs');
  });

  it('joins multiple segments with /', () => {
    expect(toBrowseHash('docs/2024/reports')).toBe('#/browse/docs/2024/reports');
  });

  it('percent-encodes spaces within a segment', () => {
    expect(toBrowseHash('hello world')).toBe('#/browse/hello%20world');
  });

  it('encodes each segment independently (spaces do not leak across segments)', () => {
    expect(toBrowseHash('a b/c d')).toBe('#/browse/a%20b/c%20d');
  });

  it('encodes reserved characters such as ? and #', () => {
    expect(toBrowseHash('a?b#c')).toBe('#/browse/a%3Fb%23c');
  });

  it('encodes a literal percent sign', () => {
    expect(toBrowseHash('100%')).toBe('#/browse/100%25');
  });

  it('preserves a trailing slash as an empty trailing segment', () => {
    expect(toBrowseHash('docs/')).toBe('#/browse/docs/');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toBrowseHash('café')).toBe('#/browse/caf%C3%A9');
  });
});

describe('toSearchHash', () => {
  it('builds a search hash from query and path', () => {
    expect(toSearchHash('hello', 'docs')).toBe('#/search?q=hello&path=docs');
  });

  it('handles empty query and path', () => {
    expect(toSearchHash('', '')).toBe('#/search?q=&path=');
  });

  it('percent-encodes spaces in both query and path', () => {
    expect(toSearchHash('hello world', 'my docs')).toBe(
      '#/search?q=hello%20world&path=my%20docs',
    );
  });

  it('encodes characters that would otherwise break the query string (& and =)', () => {
    expect(toSearchHash('a&b', 'c=d')).toBe('#/search?q=a%26b&path=c%3Dd');
  });

  it('encodes a literal percent sign', () => {
    expect(toSearchHash('100% off', 'x')).toBe('#/search?q=100%25%20off&path=x');
  });

  it('encodes a slash in the path so it survives a single path= param', () => {
    expect(toSearchHash('a', 'b/c')).toBe('#/search?q=a&path=b%2Fc');
  });

  it('encodes multi-byte (unicode) characters as UTF-8 percent sequences', () => {
    expect(toSearchHash('café', 'ñ')).toBe('#/search?q=caf%C3%A9&path=%C3%B1');
  });
});

/**
 * Round-trip property tests. These do not couple to a particular encoding
 * scheme: they assert the spec-level invariant that serializing a value and
 * parsing it back is lossless. They serve as a behavioral safety net on top of
 * the exact-format assertions above.
 */
describe('round-trip serialization (serialize -> parse is lossless)', () => {
  it.each([
    ['empty path', ''],
    ['single segment', 'docs'],
    ['multiple segments', 'docs/2024/reports'],
    ['spaces within segments', 'a b/c d'],
    ['reserved characters', 'a?b#c'],
    ['literal percent', '100%'],
    ['trailing slash', 'docs/'],
    ['unicode', 'café'],
  ])('round-trips browse path: %s', (_label, path) => {
    expect(parseHash(toBrowseHash(path))).toEqual({ view: 'browse', path, query: '' });
  });

  it.each<[string, string, string]>([
    ['empty query and path', '', ''],
    ['query only', 'hello', ''],
    ['path only', '', 'docs'],
    ['both values', 'hello world', 'my docs'],
    ['query-string-breaking chars', 'a&b', 'c=d'],
    ['plus character', 'a+b', 'c'],
    ['percent character', '100% off', 'a/b'],
    ['unicode', 'café', 'ñ'],
  ])('round-trips search route: %s', (_label, query, path) => {
    expect(parseHash(toSearchHash(query, path))).toEqual({ view: 'search', query, path });
  });
});

